request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?msg ?msgName WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "2d887704e5324e6bb2126cef061e50e9" .
  ?defs tai:belongsTo ?model .
  ?choreo tai:belongsTo ?defs .

  ?node bbo:name ?nodeName ;
        tai:belongsTo ?choreo .
  FILTER(CONTAINS(LCASE(STR(?nodeName)), LCASE("Get client to add theerlevant cost centre")))

  ?mf a bboExt:MessageFlow ;
      tai:belongsTo ?choreo ;
      bboExt:sourceRef ?src ;
      bboExt:targetRef ?tgt .
  FILTER(
    STR(?src) = COALESCE(STRAFTER(STR(?node),"#"), STR(?node)) ||
    STR(?tgt) = COALESCE(STRAFTER(STR(?node),"#"), STR(?node))
  )

  OPTIONAL {
    ?mf bboExt:messageRef ?msgRef .
    ?msg a bboExt:Message ;
         tai:belongsTo ?choreo ;
         bbo:id ?msgRef .
    ?msg bbo:name ?msgName .
  }
  OPTIONAL {
    ?mf bboExt:messageRef ?msgRef2 .
    BIND(?msgRef2 AS ?msg)
  }
  BIND(COALESCE(?msgName, STR(?msg)) AS ?msgOut)
}
LIMIT 25
